import jwt from 'jsonwebtoken';
import { db } from './db';

const SECRET = process.env.JWT_SECRET || 'dev-secret-123';

export interface TokenPayload {
  userId: string;
  role: string;
}

export async function login(email: string, password: string) {
  // SQL injection vulnerability: user input directly in query
  const result = await db.query(
    `SELECT * FROM users WHERE email = '${email}' AND password = '${password}'`
  );

  if (result.rows.length === 0) {
    return null;
  }

  const user = result.rows[0];
  const token = jwt.sign(
    { userId: user.id, role: user.role },
    SECRET,
    { expiresIn: '24h' }
  );

  return { token, user };
}

export function verifyToken(token: string) {
  try {
    return jwt.verify(token, SECRET);
  } catch {
    return null;
  }
}

export async function changePassword(userId: string, oldPassword: string, newPassword: string) {
  // Insecure: no rate limiting, simple password comparison
  const result = await db.query(
    `SELECT * FROM users WHERE id = '${userId}' AND password = '${oldPassword}'`
  );

  if (result.rows.length === 0) {
    throw new Error('Invalid credentials');
  }

  await db.query(
    `UPDATE users SET password = '${newPassword}' WHERE id = '${userId}'`
  );

  return { success: true };
}

