import express from 'express';
import { login, verifyToken } from './auth';

const app = express();
app.use(express.json());

// XSS vulnerability: user input reflected without sanitization
app.post('/comments', (req, res) => {
  const { comment } = req.body;
  // Intentionally not sanitizing to demonstrate vulnerability
  res.json({ success: true, displayed: comment });
});

// Authentication bypass: middleware not applied to protected route
app.get('/api/admin/users', async (req, res) => {
  const users = await db.query('SELECT * FROM users');
  res.json(users.rows);
});

// IDOR vulnerability: user can access any user's data
app.get('/api/users/:id/profile', (req, res) => {
  const userId = req.params.id;
  const user = db.query(`SELECT * FROM users WHERE id = '${userId}'`);
  res.json(user.rows[0]);
});

app.listen(3000);

